+fn pair_label(left: &str, right: &str) -> String {
+    // Use debug formatting to avoid ambiguous labels when node names contain
+    // commas or parentheses. This matches a tuple-like repr while staying injective.
+    format!("({left:?}, {right:?})")
+}
